import { Component, Input } from '@angular/core';
import { FaIconLibrary } from '@fortawesome/angular-fontawesome';
import { fas } from '@fortawesome/free-solid-svg-icons';
import { IconName } from '@fortawesome/fontawesome-svg-core';

@Component({
  selector: 'app-button',
  templateUrl: './button.component.html',
  styleUrls: ['./button.component.scss']
})
export class ButtonComponent {
  constructor(library: FaIconLibrary) {
    library.addIconPacks(fas);
  }

  @Input() buttonText?: string;
  @Input() iconName?: IconName;
}
<button class="app-button" [class.app-button__single-icon]="iconName && !buttonText">
    <!-- using font awesome component for setting up either trash or edit icon if iconName exists-->
    <fa-icon *ngIf="iconName" [icon]="['fas', iconName]" class="btn-icon"></fa-icon>

    <!-- if buttonText exists create the span tag and bind its label-->
    <span *ngIf="buttonText">{{ buttonText }}</span>
</button>
